export function script(input) {
  const domains = Array.isArray(input.domains) ? input.domains : [];
  const subdomains = Array.isArray(input.subdomains) ? input.subdomains : [];
  const dnsRecords = Array.isArray(input.dnsRecords) ? input.dnsRecords : [];
  const httpResponses = Array.isArray(input.httpResponses) ? input.httpResponses : [];
  const authorizationNotes = typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null;
  const hostMap = new Map();
  for (const record of dnsRecords) {
    const host = String(record?.host || record?.domain || record?.name || '').toLowerCase();
    if (!host) continue;
    const ips = Array.isArray(record?.a) ? record.a : Array.isArray(record?.ips) ? record.ips : Array.isArray(record?.A) ? record.A : [];
    hostMap.set(host, { host, dnsRecords: ips, technologies: [], statusCode: null, title: null, url: null });
  }
  for (const resp of httpResponses) {
    const url = resp?.url || resp?.finalUrl || resp?.input;
    if (typeof url !== 'string' || url.length === 0) continue;
    let host = '';
    try { host = new URL(url).hostname.toLowerCase(); } catch { host = String(resp?.host || resp?.input || '').toLowerCase(); }
    if (!host) continue;
    const existing = hostMap.get(host) || { host, dnsRecords: [], technologies: [], statusCode: null, title: null, url: null };
    existing.url = url;
    existing.statusCode = resp?.statusCode ?? existing.statusCode;
    existing.title = resp?.title ?? existing.title;
    existing.technologies = Array.isArray(resp?.technologies) ? resp.technologies : existing.technologies;
    hostMap.set(host, existing);
  }
  const score = (item) => (Number(item.statusCode) === 200 ? 2 : item.statusCode ? 1 : 0) + (Array.isArray(item.technologies) ? item.technologies.length : 0);
  const assets = Array.from(hostMap.values()).sort((a, b) => score(b) - score(a) || a.host.localeCompare(b.host));
  const technologies = Array.from(new Set(assets.flatMap((item) => (Array.isArray(item.technologies) ? item.technologies : []))));
  return {
    report: {
      summary: {
        domains,
        subdomainsFound: subdomains.length,
        resolvedHosts: dnsRecords.length,
        liveEndpoints: httpResponses.length,
        enrichedAssets: assets.length,
        technologies
      },
      authorizationNotes,
      assets: assets.slice(0, 150),
      nextSteps: [
        'Validate discovered hosts remain in authorized program scope',
        'Review live endpoints with unusual titles, technologies, or status codes',
        'Escalate to deeper recon templates for crawling and targeted testing'
      ]
    }
  };
}
